SELECT AVG(word_count) AS average_word_count
FROM content
WHERE copyscape_status = 'Not Checked';

SELECT content_id, status
FROM plagiarism_checks
WHERE status = 'Pass';

SELECT content_id 
FROM content 
WHERE is_active = 1 AND project_id IS NOT NULL;

SELECT content_id, MAX(date_updated) AS latest_update
FROM content_status
GROUP BY content_id;

SELECT writer_name
FROM writers
WHERE is_active = 1;

SELECT project_id
FROM projects
ORDER BY project_id;
